import Author from"../templates/author.js";const dashboard='\n<section>\n\t<Author />\n\n\t<section class="filter-wrap">\n\t\t<div class="container">\n\t\t\t<div class="row">\n\t\t\t\t<div class="col-lg-8 offset-lg-2 col-md-12 col-12">\n\t\t\t\t\t<ul id="js-filter-tag-wrap" class="tag-list work-tag-box filter-tag-wrap">\n\t\t\t\t\t\t<li class="tag-item control-btn select-all active">All</li>\n\t\t\t\t\t\t<li class="tag-item active">HTML5</li>\n\t\t\t\t\t\t<li class="tag-item active">HTML Email</li>\n\t\t\t\t\t\t<li class="tag-item active">CSS</li>\n\t\t\t\t\t\t<li class="tag-item active">SCSS</li>\n\t\t\t\t\t\t<li class="tag-item active">Bootstrap 5</li>\n\t\t\t\t\t\t<li class="tag-item active">JavaScript</li>\n\t\t\t\t\t\t<li class="tag-item active">jQuery 3</li>\n\t\t\t\t\t\t<li class="tag-item active">Vue.js 2</li>\n\t\t\t\t\t\t<li class="tag-item active">Owl Carousel 2</li>\n\t\t\t\t\t\t<li class="tag-item active">Gulp</li>\n\t\t\t\t\t\t<li class="tag-item active">Squarespace</li>\n\t\t\t\t\t\t<li class="tag-item active">WordPress.org</li>\n\t\t\t\t\t\t<li class="tag-item active">Adobe Photoshop</li>\n\t\t\t\t\t\t<li class="tag-item active">Adobe Illustrator</li>\n\t\t\t\t\t\t<li class="tag-item active">Adobe XD</li>\n\t\t\t\t\t\t<li class="tag-item control-btn remove-all">Remove All</li>\n\t\t\t\t\t</ul>\n\t\t\t\t</div>\n\t\t\t</div>\n\t\t</div>\n\t</section>\n\n\t<ul class="dashboard-menu-wrap">\n\t\t<li class="dashboard-menu-item"><a href="#front-end-making" data-en="Front-end Making">前端製作/切版</a></li>\n\t\t<li class="dashboard-menu-item"><a href="#front-end-cms-style" data-en="CMS">內容管理系統</a></li>\n\t\t<li class="dashboard-menu-item"><a href="#web-design" data-en="Web design">網頁設計</a></li>\n\t\t<li class="dashboard-menu-item"><a href="#graphic-design" data-en="Graphic design">平面設計/影像處理</a></li>\n\t\t<li class="dashboard-menu-item"><a href="#side-projects" data-en="Side-Projects">個人作品</a></li>\n\t</ul>\n\t\n\t<section class="dashboard-section">\n\t\t<template v-if="kinds">\n\t\t\t<template v-for="kind in kinds">\n\t\t\t\t<div class="container">\n\t\t\t\t\t<div class="row">\n\t\t\t\t\t\t<div class="col-12 col-lg-12 col-md-12">\n\t\t\t\t\t\t\t<div v-bind:id="kind.category" class="dashboard-section-header">\n\t\t\t\t\t\t\t\t<span class="section-header-title-zh">{{kind.title_ch}}</span>\n\t\t\t\t\t\t\t\t<span class="section-header-title-en">{{kind.title_en}}</span>\n\t\t\t\t\t\t\t\t<span class="section-header-des">{{kind.des}}</span>\n\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t</div>\n\t\t\t\t\t</div>\n\t\t\t\t\t<div class="row">\n\t\t\t\t\t\t<div class="col-12 col-lg-3 col-md-4 dashboard-card-wrap" v-for="(work, index) in kind.works">\n\t\t\t\t\t\t\t<router-link v-bind:to="{ name: \'detail\', params: { category: kind.category, name: work.name } }">\n\t\t\t\t\t\t\t\t<div class="dashboard-card-inner">\n\t\t\t\t\t\t\t\t\t<div class="card-image">\n\t\t\t\t\t\t\t\t\t\t<div class="pc-style">\n\t\t\t\t\t\t\t\t\t\t\t<picture>\n\t\t\t\t\t\t\t\t\t\t\t\t<source v-bind:srcset="work.webp" type="image/webp">\n\t\t\t\t\t\t\t\t\t\t\t\t<img v-bind:src="work.image" v-bind:alt="work.title" draggable="false">\n\t\t\t\t\t\t\t\t\t\t\t</picture>\n\t\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t\t\t<div class="mobile-style">\n\t\t\t\t\t\t\t\t\t\t\t<picture>\n\t\t\t\t\t\t\t\t\t\t\t\t<source v-bind:srcset="work.webp_mobile" type="image/webp">\n\t\t\t\t\t\t\t\t\t\t\t\t<img v-bind:src="work.image_mobile" v-bind:alt="work.title" draggable="false">\n\t\t\t\t\t\t\t\t\t\t\t</picture>\n\t\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t\t<div class="card-year">{{work.year}}</div>\n\t\t\t\t\t\t\t\t\t<div class="card-info-wrap">\n\t\t\t\t\t\t\t\t\t\t<div class="card-info-title" v-bind:title="work.title">{{work.title}}</div>\n\t\t\t\t\t\t\t\t\t\t<div class="card-info-subtitle-wrap">\n\t\t\t\t\t\t\t\t\t\t\t<div class="card-info-link-wrap">\n\t\t\t\t\t\t\t\t\t\t\t\t<div title="線上網站" v-if="work.link" class="link-icon icon-website"></div>\n\t\t\t\t\t\t\t\t\t\t\t\t<div title="測試站" v-if="work.demo" class="link-icon icon-demo"></div>\n\t\t\t\t\t\t\t\t\t\t\t\t<div title="Github" v-if="work.github" class="link-icon icon-github"></div>\n\t\t\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t\t\t\t<div class="card-info-des" v-bind:title="work.description">{{work.description}}</div>\n\t\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t\t\t<ul class="tag-list card-info-tags-wrap">\n\t\t\t\t\t\t\t\t\t\t\t<li class="tag-item" v-for="tag in work.tags">{{tag}}</li>\n\t\t\t\t\t\t\t\t\t\t</ul>\n\t\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t\t</div>\n\t\t\t\t\t\t\t</router-link>\n\t\t\t\t\t\t</div>\n\t\t\t\t\t</div>\n\t\t\t\t</div>\n\t\t\t</template>\n        </template>\n    </section>\n</section>\n',Dashboard={template:dashboard,data:()=>({kinds:[]}),created(){this.fetchData()},mounted:function(){$("#js-goback-btn").removeClass("show");let t=$("#js-filter-tag-wrap").find(".tag-item"),i=t.filter(".select-all"),e=t.filter(".remove-all");t.on("click",(function(a){$(this).toggleClass("active"),$(this).hasClass("select-all")&&(t.addClass("active"),e.removeClass("active")),$(this).hasClass("remove-all")&&(t.removeClass("active"),e.addClass("active"));let s=!0,n=!0;t.not(".control-btn").each((function(t){$(this).hasClass("active")||(s=!1),$(this).hasClass("active")&&(n=!1)})),$(this).hasClass("control-btn")||(s?(i.addClass("active"),e.removeClass("active")):n?(i.removeClass("active"),e.addClass("active")):(i.removeClass("active"),e.removeClass("active")));let l=[];t.filter(".active").each((function(t){l.push($(this).text().toLowerCase())})),$(".dashboard-card-wrap").filter((function(){let t=[];$(this).find(".tag-item").each((function(i){t.push($(this).text().toLowerCase())})),l.some((i=>t.indexOf(i)>=0))?$(this).fadeIn():$(this).fadeOut()}))})),$("a[href*=\\#]").click((function(){var t=$(this.hash);return $("html, body").animate({scrollTop:t.offset().top-80},600),!1}));let a=document.querySelector('meta[property="og:title"]').content,s=location.href;document.querySelector('meta[property="og:description"]').content=a,document.querySelector('meta[property="og:url"]').content=s,document.querySelector('meta[property="og:image"]').content="https://minruxie.github.io/demo_station/joyxie-portfolio/dist/assets/images/cheese.png"},methods:{fetchData(){fetch("dist/assets/data/works.json").then((t=>t.json())).then((t=>this.kinds=t))}},components:{Author:Author}};export default Dashboard;